class Solution:
    def minCost(self, nums: List[int], x: int) -> int:
        n = len(nums)
        min_total = float('inf')

        # For each possible number of operations (from 0 to n-1)
        for k in range(n):
            current_cost = 0
            # For each position i, find the minimum cost of collecting that type after up to k rotations
            for i in range(n):
                # The cost of collecting type i after k rotations is nums[(i - k) % n]
                current_cost += min(nums[(i - k) % n] for k in range(k + 1))
            min_total = min(min_total, current_cost + k * x)

        return min_total
